import { useState, useEffect, useRef, useCallback } from "react";

const PHOTO = "data:image/jpeg;base64,";

const SLAP_TEXTS = ["💋 MWAH!", "💖 LOVE!", "💗 SMOOCH!", "💕 KISS!", "💝 AWW!", "💓 THUMP!", "💘 STRUCK!"];
const REACTIONS = [
  "Ashu I love youu 💕",
  "Ashu I love youu 🥺",
  "Ashu I love youu!! 😍",
  "Ashu I love youu 💖",
  "Ashu... I love youu 😘",
  "Ashu I love youu sooo much! 💗",
  "Ashu I love youu 🌸",
  "Ashu, my heart!! 💓",
  "Ashu I love youu forever! 💝",
];

function FloatingHeart({ style }) {
  return <div style={style}>❤️</div>;
}

function Petal({ style }) {
  return <div style={style}>🌸</div>;
}

function SlapHand({ x, y, visible }) {
  return visible ? (
    <div style={{
      position: "fixed", left: x, top: y,
      fontSize: "3.5rem", pointerEvents: "none",
      transform: "translate(-50%,-60%) rotate(-30deg) scaleX(-1)",
      zIndex: 200,
      animation: "slapHand 0.35s cubic-bezier(.2,1.6,.4,1) forwards",
      filter: "drop-shadow(2px 4px 6px rgba(0,0,0,0.4))",
    }}>🤚</div>
  ) : null;
}

function Particle({ x, y, emoji, id, dx, dy }) {
  return (
    <div style={{
      position: "fixed", left: x, top: y, fontSize: "1.6rem",
      pointerEvents: "none", zIndex: 150,
      transform: "translate(-50%,-50%)",
      animation: `pflyX 0.7s ease-out forwards`,
      "--dx": `${dx}px`, "--dy": `${dy}px`,
    }}>{emoji}</div>
  );
}

const HEARTS = Array.from({length: 18}, (_, i) => ({
  id: i,
  left: `${Math.random() * 100}%`,
  size: 0.8 + Math.random() * 1.4,
  duration: 6 + Math.random() * 8,
  delay: Math.random() * 8,
  drift: (Math.random() - 0.5) * 60,
  emoji: ["❤️","💕","💗","💖","💓","💘","🌹","🌸"][Math.floor(Math.random()*8)],
}));

const PETALS = Array.from({length: 14}, (_, i) => ({
  id: i,
  left: `${Math.random() * 100}%`,
  size: 1 + Math.random() * 0.8,
  duration: 8 + Math.random() * 6,
  delay: Math.random() * 10,
}));

export default function TalkingAashi() {
  const [slaps, setSlaps] = useState(0);
  const [slapping, setSlapping] = useState(false);
  const [slapPos, setSlapPos] = useState({ x: 0, y: 0 });
  const [headTilt, setHeadTilt] = useState(0);
  const [reaction, setReaction] = useState(null);
  const [slapWord, setSlapWord] = useState("");
  const [particles, setParticles] = useState([]);
  const [cheekRed, setCheekRed] = useState(false);
  const [tailWag, setTailWag] = useState(false);
  const [blinking, setBlinking] = useState(false);
  const [earWiggle, setEarWiggle] = useState(false);
  const [heartBurst, setHeartBurst] = useState(false);
  const pIdRef = useRef(0);

  useEffect(() => {
    const blinkTimer = setInterval(() => {
      setBlinking(true);
      setTimeout(() => setBlinking(false), 120);
    }, 3000 + Math.random() * 2000);
    const tailTimer = setInterval(() => {
      setTailWag(true);
      setTimeout(() => setTailWag(false), 600);
    }, 2500);
    return () => { clearInterval(blinkTimer); clearInterval(tailTimer); };
  }, []);

  const handleSlap = useCallback((e) => {
    e.preventDefault();
    if (slapping) return;
    const clientX = e.clientX ?? e.touches?.[0]?.clientX ?? window.innerWidth / 2;
    const clientY = e.clientY ?? e.touches?.[0]?.clientY ?? window.innerHeight / 2;
    setSlapPos({ x: clientX, y: clientY });
    setSlapping(true);
    setHeadTilt(Math.random() > 0.5 ? 18 : -18);
    setCheekRed(true);
    setEarWiggle(true);
    setHeartBurst(true);
    setSlapWord(SLAP_TEXTS[Math.floor(Math.random() * SLAP_TEXTS.length)]);
    setReaction(REACTIONS[Math.floor(Math.random() * REACTIONS.length)]);
    setSlaps(s => s + 1);
    const emojis = ["💕","💖","💗","💓","💘","🌸","🌹","✨","💫","❤️"];
    const newP = Array.from({ length: 10 }, () => ({
      id: pIdRef.current++,
      x: clientX + (Math.random() - 0.5) * 60,
      y: clientY + (Math.random() - 0.5) * 60,
      emoji: emojis[Math.floor(Math.random() * emojis.length)],
      dx: (Math.random() - 0.5) * 140,
      dy: -(Math.random() * 100 + 40),
    }));
    setParticles(p => [...p, ...newP]);
    setTimeout(() => setSlapping(false), 350);
    setTimeout(() => setHeadTilt(0), 500);
    setTimeout(() => setCheekRed(false), 800);
    setTimeout(() => setEarWiggle(false), 400);
    setTimeout(() => setHeartBurst(false), 600);
    setTimeout(() => setReaction(null), 2000);
    setTimeout(() => setSlapWord(""), 700);
    setTimeout(() => setParticles(p => p.filter(x => !newP.find(n => n.id === x.id))), 900);
  }, [slapping]);

  const loveMeter = Math.min(100, slaps * 5);
  const loveLabel = loveMeter >= 100 ? "💍 SOULMATES!" : loveMeter >= 75 ? "💘 Head Over Heels!" : loveMeter >= 50 ? "💖 Deeply in Love" : loveMeter >= 25 ? "💕 Falling for You" : "🌸 A Spark...";

  return (
    <div style={{
      minHeight: "100vh",
      background: "radial-gradient(ellipse at 30% 20%, #ff8fab 0%, #ff4d6d 20%, #c9184a 45%, #590d22 100%)",
      display: "flex", flexDirection: "column",
      alignItems: "center", justifyContent: "center",
      fontFamily: "'Fredoka One', 'Comic Sans MS', cursive",
      overflow: "hidden", position: "relative",
      cursor: "pointer",
    }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Fredoka+One&display=swap');

        @keyframes slapHand {
          0% { transform:translate(-50%,-60%) rotate(-30deg) scaleX(-1) scale(0.5); opacity:0; }
          40% { transform:translate(-50%,-60%) rotate(-30deg) scaleX(-1) scale(1.3); opacity:1; }
          100% { transform:translate(-50%,-60%) rotate(-30deg) scaleX(-1) scale(0.8); opacity:0; }
        }
        @keyframes slapWord {
          0% { transform:translate(-50%,-50%) scale(0) rotate(-10deg); opacity:0; }
          40% { transform:translate(-50%,-50%) scale(1.4) rotate(-8deg); opacity:1; }
          100% { transform:translate(-50%,-50%) scale(1) rotate(-5deg) translateY(-30px); opacity:0; }
        }
        @keyframes reactionBubble {
          0% { transform:translateX(-50%) scale(0); opacity:0; }
          25% { transform:translateX(-50%) scale(1.15); opacity:1; }
          75% { transform:translateX(-50%) scale(1); opacity:1; }
          100% { transform:translateX(-50%) scale(0.9) translateY(-15px); opacity:0; }
        }
        @keyframes pflyX {
          0% { opacity:1; transform:translate(-50%,-50%) translate(0,0) scale(1); }
          100% { opacity:0; transform:translate(-50%,-50%) translate(var(--dx),var(--dy)) scale(2); }
        }
        @keyframes tailWagAnim {
          0%,100% { transform:rotate(-10deg); }
          50% { transform:rotate(30deg); }
        }
        @keyframes earWiggleAnim {
          0%,100% { transform:rotate(0deg); }
          25% { transform:rotate(-15deg); }
          75% { transform:rotate(10deg); }
        }
        @keyframes floatBody {
          0%,100% { transform:translateY(0px); }
          50% { transform:translateY(-10px); }
        }
        @keyframes floatHeart {
          0% { transform:translateY(110vh) translateX(0px) scale(0.5); opacity:0; }
          10% { opacity:1; }
          90% { opacity:0.7; }
          100% { transform:translateY(-20vh) translateX(var(--drift)) scale(1.2); opacity:0; }
        }
        @keyframes floatPetal {
          0% { transform:translateY(-60px) rotate(0deg); opacity:0; }
          10% { opacity:1; }
          100% { transform:translateY(110vh) rotate(720deg); opacity:0; }
        }
        @keyframes heartPulse {
          0%,100% { transform:scale(1); }
          50% { transform:scale(1.18); filter: drop-shadow(0 0 20px #ff4d6d); }
        }
        @keyframes heartBurstAnim {
          0% { transform:scale(1); }
          50% { transform:scale(1.35); filter: drop-shadow(0 0 40px #ff8fab); }
          100% { transform:scale(1); }
        }
        @keyframes glowPulse {
          0%,100% { box-shadow: 0 0 30px rgba(255,77,109,0.4), 0 0 60px rgba(255,143,171,0.2); }
          50% { box-shadow: 0 0 60px rgba(255,77,109,0.8), 0 0 100px rgba(255,143,171,0.4); }
        }
        @keyframes titleFloat {
          0%,100% { transform:translateY(0) rotate(-1deg); }
          50% { transform:translateY(-6px) rotate(1deg); }
        }
        @keyframes loveBarFill {
          from { width: 0%; }
        }
        @keyframes sparkle {
          0%,100% { opacity:0; transform:scale(0) rotate(0deg); }
          50% { opacity:1; transform:scale(1) rotate(180deg); }
        }
        .cat-body { animation: floatBody 3s ease-in-out infinite; }
        .tail { transform-origin:210px 320px; animation:${tailWag ? "tailWagAnim 0.6s ease-in-out" : "none"}; }
        .ear-left { transform-origin:95px 80px; animation:${earWiggle ? "earWiggleAnim 0.4s ease-out" : "none"}; }
        .ear-right { transform-origin:185px 80px; animation:${earWiggle ? "earWiggleAnim 0.4s ease-out 0.05s" : "none"}; }
        .cat-glow { animation: glowPulse 2.5s ease-in-out infinite; }
        .heart-burst { animation: ${heartBurst ? "heartBurstAnim 0.6s ease-out" : "heartPulse 1.8s ease-in-out infinite"}; }
      `}</style>

      {/* Floating hearts background */}
      {HEARTS.map(h => (
        <div key={h.id} style={{
          position:"fixed", left:h.left, bottom:"-60px",
          fontSize:`${h.size}rem`, pointerEvents:"none", zIndex:1,
          "--drift": `${h.drift}px`,
          animation:`floatHeart ${h.duration}s ease-in-out ${h.delay}s infinite`,
        }}>{h.emoji}</div>
      ))}

      {/* Falling petals */}
      {PETALS.map(p => (
        <div key={p.id} style={{
          position:"fixed", left:p.left, top:"-40px",
          fontSize:`${p.size}rem`, pointerEvents:"none", zIndex:1,
          animation:`floatPetal ${p.duration}s linear ${p.delay}s infinite`,
        }}>🌸</div>
      ))}

      {/* Decorative sparkles */}
      {[...Array(6)].map((_,i) => (
        <div key={i} style={{
          position:"fixed",
          left:`${10 + i*16}%`, top:`${15 + (i%3)*25}%`,
          fontSize:"1.2rem", pointerEvents:"none", zIndex:1, opacity:0.6,
          animation:`sparkle ${2+i*0.4}s ease-in-out ${i*0.5}s infinite`,
        }}>✨</div>
      ))}

      {/* Title */}
      <h1 style={{
        fontSize:"clamp(1.8rem,5vw,3rem)", color:"#fff",
        textShadow:"0 0 20px rgba(255,143,171,0.8), 3px 3px 0 rgba(89,13,34,0.5)",
        marginBottom:"0.2rem", letterSpacing:"3px", zIndex:10,
        animation:"titleFloat 3s ease-in-out infinite",
      }}>💖 Talking Aashi 💖</h1>

      <p style={{
        color:"rgba(255,220,230,0.9)", fontSize:"0.95rem",
        marginBottom:"0.8rem", letterSpacing:"2px", zIndex:10,
        fontStyle:"italic",
      }}>~ tap her to feel the love ~</p>

      {/* Love meter */}
      <div style={{
        width:"clamp(200px,50vw,320px)", marginBottom:"1.2rem", zIndex:10,
      }}>
        <div style={{
          display:"flex", justifyContent:"space-between",
          color:"#ffb3c6", fontSize:"0.85rem", marginBottom:"4px",
          letterSpacing:"1px",
        }}>
          <span>💕 Love Meter</span>
          <span>{loveLabel}</span>
        </div>
        <div style={{
          background:"rgba(255,255,255,0.15)", borderRadius:"50px",
          height:"14px", overflow:"hidden",
          border:"2px solid rgba(255,180,200,0.4)",
          boxShadow:"inset 0 2px 8px rgba(0,0,0,0.2)",
        }}>
          <div style={{
            width:`${loveMeter}%`,
            height:"100%",
            background:"linear-gradient(90deg, #ff8fab, #ff4d6d, #ff006e)",
            borderRadius:"50px",
            boxShadow:"0 0 12px rgba(255,77,109,0.8)",
            transition:"width 0.5s cubic-bezier(.2,1,.4,1)",
          }}/>
        </div>
        <div style={{
          textAlign:"center", color:"#ffb3c6",
          fontSize:"0.8rem", marginTop:"3px",
        }}>{slaps} love taps 💗</div>
      </div>

      {/* Cat character */}
      <div className="cat-body cat-glow" onClick={handleSlap} onTouchStart={handleSlap}
        style={{
          position:"relative", width:280, height:430,
          userSelect:"none", cursor:"pointer", zIndex:10,
          borderRadius:"50%",
        }}>

        {/* Big pulsing heart background */}
        <div className="heart-burst" style={{
          position:"absolute", top:"50%", left:"50%",
          transform:"translate(-50%,-50%)",
          fontSize:"22rem", opacity:0.06, pointerEvents:"none", zIndex:0,
          lineHeight:1,
        }}>❤️</div>

        <svg width="280" height="430" viewBox="0 0 280 430" style={{overflow:"visible", position:"relative", zIndex:2}}>
          <defs>
            <clipPath id="faceClip"><circle cx="140" cy="150" r="62"/></clipPath>
            <radialGradient id="headGrad" cx="40%" cy="35%">
              <stop offset="0%" stopColor="rgba(255,255,255,0.35)"/>
              <stop offset="100%" stopColor="rgba(0,0,0,0.08)"/>
            </radialGradient>
            <radialGradient id="bodyGrad" cx="40%" cy="30%">
              <stop offset="0%" stopColor="rgba(255,255,255,0.25)"/>
              <stop offset="100%" stopColor="rgba(0,0,0,0.12)"/>
            </radialGradient>
            <radialGradient id="roseBody" cx="50%" cy="40%">
              <stop offset="0%" stopColor="#ff8fab"/>
              <stop offset="60%" stopColor="#ff4d6d"/>
              <stop offset="100%" stopColor="#c9184a"/>
            </radialGradient>
            <radialGradient id="roseHead" cx="45%" cy="35%">
              <stop offset="0%" stopColor="#ffb3c6"/>
              <stop offset="60%" stopColor="#ff85a1"/>
              <stop offset="100%" stopColor="#e05577"/>
            </radialGradient>
            <filter id="glow">
              <feGaussianBlur stdDeviation="3" result="coloredBlur"/>
              <feMerge><feMergeNode in="coloredBlur"/><feMergeNode in="SourceGraphic"/></feMerge>
            </filter>
          </defs>

          {/* TAIL */}
          <g className="tail">
            <path d="M 200 320 Q 270 300 280 240 Q 290 180 240 170" stroke="#ff4d6d" strokeWidth="22" fill="none" strokeLinecap="round"/>
            <path d="M 200 320 Q 270 300 280 240 Q 290 180 240 170" stroke="#ffb3c6" strokeWidth="12" fill="none" strokeLinecap="round"/>
            <ellipse cx="237" cy="165" rx="18" ry="14" fill="#ff4d6d" transform="rotate(-20,237,165)"/>
            <ellipse cx="237" cy="165" rx="10" ry="7" fill="#ffccd5" transform="rotate(-20,237,165)"/>
            {/* Heart on tail tip */}
            <text x="224" y="155" fontSize="18" textAnchor="middle" filter="url(#glow)">💕</text>
          </g>

          {/* BODY */}
          <ellipse cx="140" cy="310" rx="90" ry="105" fill="url(#roseBody)"/>
          <ellipse cx="140" cy="310" rx="90" ry="105" fill="url(#bodyGrad)"/>
          {/* Belly */}
          <ellipse cx="140" cy="322" rx="55" ry="70" fill="rgba(255,220,230,0.7)"/>
          {/* Heart on belly */}
          <text x="140" y="320" fontSize="28" textAnchor="middle" dominantBaseline="middle" filter="url(#glow)">❤️</text>
          {/* Belly stripes */}
          <path d="M115 280 Q140 273 165 280" stroke="rgba(255,150,180,0.5)" strokeWidth="2.5" fill="none" strokeLinecap="round"/>
          <path d="M110 297 Q140 290 170 297" stroke="rgba(255,150,180,0.4)" strokeWidth="2" fill="none" strokeLinecap="round"/>

          {/* ARMS */}
          <path d="M 68 280 Q 50 330 80 400" stroke="#ff4d6d" strokeWidth="32" strokeLinecap="round" fill="none"/>
          <path d="M 212 280 Q 230 330 200 400" stroke="#ff4d6d" strokeWidth="32" strokeLinecap="round" fill="none"/>

          {/* PAWS */}
          <ellipse cx="80" cy="405" rx="30" ry="18" fill="#ff4d6d"/>
          <ellipse cx="80" cy="405" rx="20" ry="11" fill="#ffccd5"/>
          {[68,78,88].map((x,i)=><ellipse key={i} cx={x} cy={411} rx="5" ry="4" fill="#ffb3c6"/>)}
          <ellipse cx="200" cy="405" rx="30" ry="18" fill="#ff4d6d"/>
          <ellipse cx="200" cy="405" rx="20" ry="11" fill="#ffccd5"/>
          {[188,198,208].map((x,i)=><ellipse key={i} cx={x} cy={411} rx="5" ry="4" fill="#ffb3c6"/>)}

          {/* NECK */}
          {/* Collar with hearts */}
          <ellipse cx="140" cy="218" rx="42" ry="18" fill="#c9184a"/>
          <ellipse cx="140" cy="213" rx="42" ry="14" fill="#ff4d6d"/>
          {[110,130,150,170].map((x,i)=>(
            <text key={i} x={x} y="217" fontSize="10" textAnchor="middle" dominantBaseline="middle">♥</text>
          ))}
          {/* Collar gem */}
          <ellipse cx="140" cy="222" rx="8" ry="6" fill="#ff006e"/>
          <ellipse cx="138" cy="220" rx="3" ry="2" fill="rgba(255,255,255,0.7)"/>

          {/* HEAD */}
          <g style={{
            transformOrigin:"140px 155px",
            transform:`rotate(${headTilt}deg) translateX(${headTilt > 0 ? 8 : headTilt < 0 ? -8 : 0}px)`,
            transition: slapping ? "none" : "transform 0.4s cubic-bezier(.2,2,.4,1)",
          }}>
            {/* EARS */}
            <g className="ear-left">
              <polygon points="75,105 92,52 128,98" fill="#ff4d6d"/>
              <polygon points="86,100 98,66 116,96" fill="#ffb3c6"/>
            </g>
            <g className="ear-right">
              <polygon points="152,98 188,52 205,105" fill="#ff4d6d"/>
              <polygon points="164,96 182,66 194,100" fill="#ffb3c6"/>
            </g>
            {/* Ear hearts */}
            <text x="100" y="82" fontSize="11" textAnchor="middle">💗</text>
            <text x="180" y="82" fontSize="11" textAnchor="middle">💗</text>

            {/* HEAD base */}
            <circle cx="140" cy="155" r="86" fill="url(#roseHead)"/>
            <circle cx="140" cy="155" r="86" fill="url(#headGrad)"/>

            {/* Glow ring around head */}
            <circle cx="140" cy="155" r="88" fill="none" stroke="rgba(255,143,171,0.5)" strokeWidth="4" filter="url(#glow)"/>

            {/* PHOTO */}
            <image href={PHOTO} x={78} y={88} width="124" height="124" clipPath="url(#faceClip)" preserveAspectRatio="xMidYMid slice"/>
            <circle cx="140" cy="150" r="62" fill="none" stroke="#ff4d6d" strokeWidth="3.5"/>

            {/* Rosy cheeks always */}
            <ellipse cx="90" cy="170" rx="20" ry="12" fill="rgba(255,100,130,0.25)"/>
            <ellipse cx="190" cy="170" rx="20" ry="12" fill="rgba(255,100,130,0.25)"/>

            {/* Cheek flush on slap */}
            {cheekRed && <>
              <ellipse cx="90" cy="168" rx="26" ry="16" fill="rgba(255,40,80,0.45)"/>
              <ellipse cx="190" cy="168" rx="26" ry="16" fill="rgba(255,40,80,0.35)"/>
            </>}

            {/* Whiskers - rose gold */}
            <g stroke="#c9184a" strokeWidth="1.5" strokeLinecap="round" opacity="0.65">
              <line x1="78" y1="163" x2="112" y2="168"/>
              <line x1="78" y1="173" x2="112" y2="173"/>
              <line x1="78" y1="183" x2="112" y2="178"/>
              <line x1="202" y1="163" x2="168" y2="168"/>
              <line x1="202" y1="173" x2="168" y2="173"/>
              <line x1="202" y1="183" x2="168" y2="178"/>
            </g>

            {/* Nose + mouth */}
            <polygon points="140,190 135,197 145,197" fill="#ff006e"/>
            <path d="M135,197 Q132,204 128,202 M145,197 Q148,204 152,202" stroke="#c9184a" strokeWidth="1.8" fill="none" strokeLinecap="round"/>

            {/* Blink */}
            {blinking && <>
              <ellipse cx="118" cy="148" rx="13" ry="5" fill="#ff85a1"/>
              <ellipse cx="162" cy="148" rx="13" ry="5" fill="#ff85a1"/>
            </>}

            {/* Small sparkles on head */}
            <text x="68" y="108" fontSize="12" opacity="0.8">✨</text>
            <text x="200" y="108" fontSize="12" opacity="0.8">✨</text>
          </g>
        </svg>

        {/* SLAP word */}
        {slapWord && (
          <div style={{
            position:"absolute", top:"12%", left:"50%",
            fontSize:"2.4rem", fontWeight:900, color:"#fff",
            textShadow:"0 0 20px #ff4d6d, 2px 2px 0 #c9184a",
            pointerEvents:"none", zIndex:50,
            animation:"slapWord 0.7s ease-out forwards",
            letterSpacing:"-1px",
          }}>{slapWord}</div>
        )}

        {/* Reaction bubble */}
        {reaction && (
          <div style={{
            position:"absolute", top:"-75px", left:"50%",
            background:"linear-gradient(135deg, #fff0f3, #ffe0e8)",
            borderRadius:"24px",
            padding:"12px 22px", fontSize:"1.05rem", fontWeight:"bold",
            color:"#c9184a", whiteSpace:"nowrap",
            boxShadow:"0 8px 30px rgba(201,24,74,0.3), 0 0 0 2px #ff4d6d",
            animation:"reactionBubble 2s ease-out forwards",
            zIndex:60,
          }}>
            {reaction}
            <div style={{
              position:"absolute", bottom:"-13px", left:"50%",
              transform:"translateX(-50%)", width:0, height:0,
              borderLeft:"11px solid transparent", borderRight:"11px solid transparent",
              borderTop:"13px solid #fff0f3",
            }}/>
          </div>
        )}
      </div>

      {/* Bottom romantic tag */}
      <div style={{
        marginTop:"1rem", fontSize:"1rem", color:"rgba(255,220,230,0.95)",
        letterSpacing:"2px", zIndex:10, textAlign:"center",
        textShadow:"0 0 10px rgba(255,143,171,0.5)",
      }}>
        {loveMeter >= 100 ? "💍 You two are meant to be! 💍"
          : loveMeter >= 75 ? "💘 So deeply in love~"
          : loveMeter >= 50 ? "💖 Love is blossoming 🌹"
          : loveMeter >= 25 ? "🌸 Something's in the air..."
          : "💕 Tap to unlock the romance..."}
      </div>

      {slaps > 0 && (
        <button onClick={()=>setSlaps(0)} style={{
          marginTop:"0.9rem", zIndex:10,
          background:"rgba(255,255,255,0.12)",
          backdropFilter:"blur(10px)",
          border:"2px solid rgba(255,180,200,0.5)",
          color:"#ffb3c6", borderRadius:"50px",
          padding:"8px 24px", fontFamily:"inherit",
          fontSize:"0.9rem", cursor:"pointer",
          letterSpacing:"1px",
          transition:"all 0.2s",
        }}>🔄 Start Over</button>
      )}

      <SlapHand x={slapPos.x} y={slapPos.y} visible={slapping}/>
      {particles.map(p=><Particle key={p.id} {...p}/>)}
    </div>
  );
}
